  T.tgo_v4 = {
    name: "Готовность к обучению — ТГО (В4)",
    blockSize: 30,
    questions: [
      { id: "tgo4_1", text: "В гимназии все ученики знают хотя бы один из иностранных языков — английский или французский, а некоторые — оба языка. 85% всех ребят знают английский язык и 75% знают французский. Определите, какая часть учащихся знает оба языка", options: ["30%", "35%", "40%", "45%", "60%"], correct: [4], explanation: "Все знают хотя бы один язык: A∪B = 100%. Оба языка: 85% + 75% − 100% = 60%." },
      { id: "tgo4_2", text: "Разные кружки посещают 500 учеников школы. Сколько учеников посещают кружок физики (по диаграмме)", image: "img/gko/v4_tgo_img1.png", options: ["150 ученика", "85 учеников", "140 учеников", "130 ученика", "125 учеников"], correct: [4], explanation: "По диаграмме физика — 25%: 500 · 0,25 = 125 учеников." },
      { id: "tgo4_3", text: "Числа в фигурах расположены в определенной закономерности. Соблюдая эту закономерность, найдите число x", image: "img/gko/v4_tgo_img2.png", options: ["154", "19", "143", "65", "28"], correct: [2], explanation: "Закономерность: произведение верхних углов минус произведение нижних: 8·12 − 7·5 = 61; 11·14 − 23·2 = 108; значит x = 35·7 − 17·6 = 245 − 102 = 143." },
      { id: "tgo4_4", text: "Сравните величины. Величина А: корень уравнения 56(x – 1) = 7x – 7. Величина B: корень уравнения 12x – 9 = 8x + 7", options: ["величина A больше величины B", "величина A равна величине B", "взаимосвязь между величинами не может быть определена из данной информации", "величина B больше величины A"], correct: [3], explanation: "A: 56x − 56 = 7x − 7 → 49x = 49 → x = 1. B: 12x − 9 = 8x + 7 → 4x = 16 → x = 4. B > A." },
      { id: "tgo4_5", text: "Длина отрезка EF на рисунке будет равна", image: "img/gko/v4_tgo_img3.png", options: ["5", "3√2", "4", "√7"], correct: [2], explanation: "По вертикали: справа BD + DC = 6 + 4 = 10 — уровень F и G. Подъём E над этим уровнем: 8 − 4 = 4 по вертикали при смещении E над F, откуда EF = 4. (Вариант E в исходнике обрезан; рисунок не в масштабе.)" },
      { id: "tgo4_6", text: "Пусть x — корень уравнения 5 + (7x − 12)/3 = x + 13. Найти 2x", options: ["8", "11", "13", "9", "18"], correct: [4], explanation: "Умножаем на 3: 15 + 7x − 12 = 3x + 39 → 4x = 36 → x = 9, значит 2x = 18." },
      { id: "tgo4_7", text: "Сравните величины. Величина А: корень уравнения −8(6x − 15) = 24. Величина B: корень уравнения 12x − 9 = 4x + 7", options: ["взаимосвязь между величинами не может быть определена из данной информации", "величина B больше величины A", "величина A больше величины B", "величина A равна величине B"], correct: [3], explanation: "A: 6x − 15 = −3 → x = 2. B: 8x = 16 → x = 2. Величины равны." },
      { id: "tgo4_8", text: "Аня и Таня вместе весят 40 кг, Таня и Маня – 50 кг, Маня и Ваня – 90 кг, Ваня и Даня – 100 кг, Даня и Аня – 60 кг. Определить вес Тани", options: ["30", "20", "35", "40", "45"], correct: [1], explanation: "Сумма всех пяти уравнений: 2(А+Т+М+В+Д) = 340 → сумма = 170. Т+М = 50 и В+Д = 100 → Аня = 170 − 150 = 20 кг → Таня = 40 − 20 = 20 кг." },
      { id: "tgo4_9", text: "Деревянный кубик покрасили со всех сторон, потом распилили его на 27 одинаковых кубиков. Сколько кубиков среди них не имеют ни одной окрашенной грани", options: ["4", "8", "12", "6", "1"], correct: [4], explanation: "В кубе 3×3×3 неокрашенным остаётся только центральный кубик — 1 штука." },
      { id: "tgo4_10", text: "Сравните величины. Величина А: 4/5 ц. Величина B: 82 кг", options: ["величина A меньше величины B", "величина B меньше величины A", "взаимосвязь между величинами не может быть определена из данной информации", "величина A равна величине B"], correct: [0], explanation: "4/5 центнера = 0,8 · 100 = 80 кг < 82 кг, значит A меньше B. (В исходнике опечатка «ч» вместо «ц»; если буквально сравнивать время с массой — связь не определить.)" },
      { id: "tgo4_11", text: "При каком значении буквы выражение 3a / (59 – a) не имеет смысла", options: ["a = 59/3", "a = 3/59", "a = 59", "a — любое число", "a ≥ 59"], correct: [2], explanation: "Дробь не имеет смысла при нулевом знаменателе: 59 − a = 0 → a = 59." },
      { id: "tgo4_12", text: "Если (5a²)b² = 75, тогда чему равно (ab)²", options: ["15", "45", "225", "235", "25"], correct: [0], explanation: "5a²b² = 75 → a²b² = 15, а (ab)² = a²b² = 15." },
      { id: "tgo4_13", text: "В обыкновенном наборе домино 28 косточек. Определите, сколько косточек содержал бы набор домино, если бы значения, указанные на косточках, изменялись не от 0 до 6, а от 0 до 9", options: ["42", "40", "38", "45", "55"], correct: [4], explanation: "Число косточек = C(n+1, 2) + (n+1) при значениях 0..n. Для 0..9: пар различных C(10,2) = 45 плюс 10 дублей = 55." },
      { id: "tgo4_14", text: "Количество двузначных чисел, которые при делении на 8 дают в остатке 5", options: ["10", "11", "9", "13", "12"], correct: [1], explanation: "Числа вида 8k+5 от 13 до 93: 13, 21, 29, 37, 45, 53, 61, 69, 77, 85, 93 — всего 11." },
      { id: "tgo4_15", text: "Урожайность сахарной свеклы: 1-й год — 360 ц/га, 2-й год — 396 ц/га. Урожай третьего года вырос на 5% по сравнению со вторым. Найдите урожай за третий год и средний урожай с 1 га", options: ["422,3; 390,8", "432,2; 386,5", "415,8; 390,6", "425,8; 379,8", "425,2; 388,4"], correct: [2], explanation: "3-й год: 396 · 1,05 = 415,8 ц. Средний: (360 + 396 + 415,8) / 3 = 1171,8 / 3 = 390,6 ц." },
      { id: "tgo4_16", text: "«Водяные лютики… когда наступает период цветения — максимально … период вегетационного сезона летом, конец июля и первая декада августа — они поднимаются к поверхности и зацветают».", options: ["частый", "длинный", "холодный", "тёплый", "короткий"], correct: [3], explanation: "Конец июля — начало августа — максимально ТЁПЛЫЙ период сезона; цветение приурочено к теплу." },
      { id: "tgo4_17", text: "«Молекулярное облако содержит … деятельности звезд предыдущих поколений… солнечное содержание и содержание для молекулярных облаков то же самое – … где-то на 85% – это водород…»", options: ["предпосылки, доминанта", "предпосылки, признаки", "следы, доминанта", "следы, признаки", "условия, доминанта"], correct: [2], explanation: "Облако содержит СЛЕДЫ деятельности прошлых звёзд (принесённые тяжёлые элементы); водород на 85% — ДОМИНАНТА состава." },
      { id: "tgo4_18", text: "«Очереди угря активируют двигательные нейроны, управляющие … жертвы… чтобы … жертву, как только она обнаружена, что предотвращает бегство».", options: ["мозгом, обездвижить", "мышцами, обездвижить", "мозгом, стимулировать", "сознанием, обездвижить", "мышцами, стимулировать"], correct: [1], explanation: "Двигательные нейроны управляют МЫШЦАМИ; чтобы предотвратить бегство, жертву нужно ОБЕЗДВИЖИТЬ." },
      { id: "tgo4_19", passageId: "p_tgo4_bosch", text: "Данный текст рассказывает о", options: ["философских трудах Эразма Роттердамского", "жизненном и творческом пути Иеронима Босха", "голландском художнике Боутсе", "женитьбе Босха"], correct: [1], explanation: "Текст последовательно описывает происхождение, творчество и жизнь Босха. Остальные варианты — лишь отдельные детали. (Вариант E в исходнике обрезан.)" },
      { id: "tgo4_20", passageId: "p_tgo4_bosch", text: "Основная мысль четвёртого абзаца: рассказ", options: ["о деревне Оерошорт", "о творчестве Босха", "об удачной женитьбе Босха", "о материальном статусе Босха", "об образе жизни Босха"], correct: [4], explanation: "Абзац о том, где Босх поселился, что не покидал окрестностей города, был общительным и любознательным — это описание образа жизни." },
      { id: "tgo4_21", passageId: "p_tgo4_bosch", text: "В первом абзаце текста рассказывается о", options: ["происхождении Босха", "монастырях Хертогенбоса", "росписях Антониуса ван Акена", "картинах Яна ван Акена", "биографии Антониуса ван Акена"], correct: [0], explanation: "Первый абзац — где и когда родился Босх и что его отец и дед были живописцами, т.е. о происхождении художника." },
      { id: "tgo4_22", passageId: "p_tgo4_gobi", text: "Ключевые слова текста", options: ["местность, Кызылкумы", "половина, Китай", "территория, Монголия", "пустыня, Гоби", "море, Каракумы"], correct: [3], explanation: "Текст целиком о пустыне Гоби — это и есть ключевые слова." },
      { id: "tgo4_23", passageId: "p_tgo4_gobi", text: "Наиболее подходящее по смыслу заглавие к тексту", options: ["Пустыня Гоби", "Особенности Гоби", "Климат пустыни Гоби", "Гоби, Каракумы и Кызылкумы", "Облик пустыни Гоби"], correct: [1], explanation: "Смысл текста — Гоби «не совсем пустыня»: особые осадки, суровые зимы, тридцать три разных Гоби. Заглавие «Особенности Гоби» отражает это точнее всего." },
      { id: "tgo4_24", passageId: "p_tgo4_gobi", text: "Коммуникативная цель текста — описать", options: ["пустыни Монголии и Китая", "географическое расположение Гоби", "условия жизни людей в пустыне", "природу пустыни Гоби", "климатические особенности Гоби"], correct: [4], explanation: "Основное содержание — осадки, суровые зимы, различие местностей по климату, т.е. климатические особенности Гоби." },
      { id: "tgo4_25", passageId: "p_tgo4_guilin", text: "Коммуникативная цель текста заключается в", options: ["описании достопримечательностей города Гуйлинь", "перечислении названий мест Гуйлиня", "описании древних пагод города Гуйлинь", "описании пейзажа китайского города Гуйлинь", "определении происхождения названия Гуйлинь"], correct: [0], explanation: "Текст знакомит с достопримечательностями: холм «Хобот слона», пагода, пещера Воды и Луны, гора Фубо, парки и скалы." },
      { id: "tgo4_26", passageId: "p_tgo4_guilin", text: "Наиболее подходящий заголовок к данному тексту", options: ["Романтичные окрестности Гуйлиня", "Красоты Гуйлиня", "Достопримечательности Гуйлиня", "Пещеры Воды и Луны – главные достопримечательности Гуйлиня", "Холм «Хобот слона» – символ Гуйлиня"], correct: [1], explanation: "Текст о поэтической красоте города в целом (пейзаж, названия, настроение) — обобщающий заголовок «Красоты Гуйлиня»." },
      { id: "tgo4_27", passageId: "p_tgo4_guilin", text: "Основная мысль второго абзаца данного текста", options: ["гуйлинский лиризм достопримечательностей и их названий", "улицы, горы и парки Гуйлиня", "лиричность гуйлинского пейзажа", "поэтичность названий локусов Гуйлиня", "богатая народная фантазия гуйлинцев"], correct: [0], explanation: "Абзац объединяет две мысли: лиричность пейзажа И поэтичность названий — вариант A охватывает обе; C и D по отдельности уже." },
      { id: "tgo4_28", passageId: "p_tgo4_rain", text: "Аннотацией, подходящей к обоим текстам, является предложение …", options: ["в данном тексте приводятся общие характеристики дождя, указываются условия превращения кристаллов льда в капли", "данный текст описывает дождь как разновидность атмосферных осадков, указываются четыре фактора, отвечающих за его возникновение", "в данном тексте приводятся общие характеристики дождя, указывается размер капель и температура выпадения дождя", "данный текст описывает дождь как разновидность атмосферных осадков, указывает на некоторые факторы его образования (вариант обрезан в исходнике)", "данный текст описывает дождь как разновидность атмосферных осадков, указывает на факторы появления дождя и науки, изучающие данное явление (вариант обрезан в исходнике)"], correct: [3], explanation: "Общая для обоих текстов аннотация должна быть обобщённой: «дождь — разновидность осадков + некоторые факторы образования». A и C — только текст 1, B и E — детали только текста 2 (четыре фактора, науки)." },
      { id: "tgo4_29", passageId: "p_tgo4_rain", text: "Утверждением, верным для обоих текстов, является …", options: ["из облака выпадают кристаллы, только позже они тают, превращаясь в дождевые капли", "существуют всего 4 фактора, отвечающих за возникновение дождя", "дождь – наиболее часто встречающаяся разновидность атмосферных осадков", "дождь – это разновидность атмосферных осадков, которые выпадают в виде капель жидкости разного размера", "дождь обычно выпадает из смешанных облаков"], correct: [3], explanation: "Оба текста говорят о дожде как об осадках в виде капель разного размера (текст 1: диаметр 0,5–7 мм; текст 2: «капли разнокалиберные»). A и E — только текст 1, B и C — только текст 2." },
      { id: "tgo4_30", passageId: "p_tgo4_rain", text: "Ключевыми словами к обоим текстам являются …", options: ["капли, облака, осадки, водяной пар", "водяной пар, капли, ледяные кристаллы, перенасыщение, морось", "осадки, облака, водяной пар, капли, ледяные кристаллы, перенасыщение", "капли, облака, тучи, ливень, водяной пар, разнокалиберный, осадкометр", "осадки, капли, облака, тучи, ливень, водяной пар, движение воздуха"], correct: [0], explanation: "Общие для ОБОИХ текстов слова: капли, облака, осадки, водяной пар. Кристаллы/перенасыщение/морось — только текст 1; тучи/ливень/осадкометр — только текст 2." }
    ],
    passages: {
      p_tgo4_bosch: {
        title: "Текст: Иероним Босх",
        text: "Йероон ван Акен, прозванный Босхом, родился в Хертогенбосе около 1450 года в семье художников. Его отец и дед, Антониус и Ян ван Акены, также были живописцами. В городском архиве до сих пор хранится большое число заключенных с ними договоров на изготовление росписей и картин для различных храмов и монастырей.\nПо-видимому, учителями Босха были не только его отец, но и приезжавший в город и подолгу живший в нем известный голландский художник Д. Боутс. Иероним впервые упоминается в 1480 году в качестве члена религиозного «Братства Богородицы», которое спустя несколько лет он возглавил. В 1489 году ему поручили исполнить две створки алтаря для капеллы его братства в соборе Св. Иоанна. Известно, что эта работа получила высокую оценку Филиппа Красивого, будущего короля Кастилии. Примерно в то же время Босх выполнил и эскизы витража капеллы. На протяжении этого периода он участвовал в оформлении шествий и таинств, что не прошло бесследно для его творчества – Иероним Босх стал известен еще при жизни.\nПосле женитьбы Босх поселился в небольшой пригородной деревне Оерошорт, где получил в приданое за своей женой дом и обширный участок земли. Известно, что он никогда не покидал ближайших окрестностей своего города, хотя был человеком общительным и любознательным.\nБосх был знаком и на протяжении многих лет поддерживал дружеские отношения с Эразмом Роттердамским, мотивы книг которого часто встречаются на его картинах."
      },
      p_tgo4_gobi: {
        title: "Текст: Пустыня Гоби",
        text: "Территория Гоби занимает всю южную половину Монголии, а заодно прихватывает изрядную часть Китая. На картах до сих пор она значится как «пустыня», хотя это и не совсем верно.\nВо-первых, осадков в Гоби выпадает не так уж мало: 200–300 миллиметров, то есть раза в полтора больше, чем положено классическим пустынным районам. Поднятая на 900 метров над уровнем моря, она к тому же отличается суровыми зимами, совсем не характерными, например, для соседних Каракумов или Кызылкума.\nВо-вторых, понятие Гоби включает в себя несколько совершенно различных по климату и облику местностей. Не зря монголы говорят: «У нас тридцать три Гоби, и все разные!»"
      },
      p_tgo4_guilin: {
        title: "Текст: Город Гуйлинь",
        text: "Символом своего города жители Гуйлиня (Китай) считают холм с выразительным названием «Хобот слона» на берегу Лицзяна. Он действительно похож на слона, опустившего хобот в воду. На вершине холма высится древняя пагода, построенная в XIV веке, а у подножья находится вход в пещеру Воды и Луны. В полнолуние отсюда можно любоваться удивительно красивым отражением ночного светила в водах спокойной реки.\nЛиричность окружающего пейзажа в сочетании с вековыми традициями китайской поэзии определили общее поэтическое настроение, пронизывающее все окружающее как в самом городе Гуйлинь, так и в его окрестностях. Даже названия отдельных мест здесь звучат подобно строкам старинных стихотворений, заставляя поражаться народной фантазией. Достаточно пройтись по городу, чтобы убедиться в этом: на улицах Гуйлиня путешественник встретит и гору Фубо («Колышащейся волны»), и парк Уединенной Красоты, и скалы Семи Звёзд, и горы Парчового узора."
      },
      p_tgo4_rain: {
        title: "Два текста: Дождь",
        text: "Текст 1. Дождь — атмосферные осадки, выпадающие из облаков в виде капель жидкости со средним диаметром от 0,5 до 6—7 мм. Жидкие осадки с меньшим диаметром капель называются моросью.\nДождь выпадает, как правило, из смешанных облаков, содержащих при температурах ниже 0°C переохлаждённые капли и ледяные кристаллы. Упругость насыщения водяного пара над каплями больше, чем над ледяными кристаллами при той же температуре, поэтому облако, даже не насыщенное водяным паром по отношению к каплям воды, будет перенасыщено по отношению к кристаллам, что приводит к росту кристаллов при одновременном испарении капель. Укрупняясь и утяжеляясь, кристаллы выпадают из облака. Входя в нижнюю часть облака или под него в слои с температурой 0 °C, они тают, превращаясь в дождевые капли.\n\nТекст 2. Дождь — наиболее часто встречающаяся разновидность атмосферных осадков. Еще в начальной школе нам сообщают, откуда появляется дождь. Однако помимо стандартных объяснений причин появления этого жидкого вида осадков существует еще множество любопытных фактов и уточнений. Например, почему капли дождя разнокалиберные? Или почему из одного небольшого облачка может разразиться страшный ливень, а небо, затянутое черными тучами, способно напугать, но не пролиться и каплей воды?\nЕсли рассматривать причину появления дождя с научной точки зрения, то следует обратиться к метеорологии и климатологии. Именно эти дисциплины изучают все виды осадков. Наука определяет четыре фактора, отвечающих за возникновение дождя: восходящее движение воздуха; достаточное содержание водяного пара в воздухе; пересечение теплых и холодных потоков воздуха; возвышенный рельеф. Измеряют осадки особым прибором — осадкометром (мм/год)."
      }
    }
  };

